export function buildBgUri(svg, bg, fg) {
  if (!svg) return "";
  const filled = svg.split("{{BG}}").join(bg).split("{{FG}}").join(fg);
  return 'url("data:image/svg+xml,' + encodeURIComponent(filled) + '")';
}
export const BG_TEMPLATE_MAP = Object.fromEntries(SECTION_BG_TEMPLATES.map(t => [t.key, t.svg]));
export const BG_TEMPLATE_INK = Object.fromEntries(SECTION_BG_TEMPLATES.map(t => [t.key, t.ink || t.svg]));
